function AdminUserManagement() {
    useEffect(() => {
        document.title = "MISHTIKA - User Management";
    }, []);

    const [users, setUsers] = useState([]);
    const [showModal, setShowModal] = useState(false);
    const [userToDelete, setUserToDelete] = useState(null);
    const [error, setError] = useState('');


    useEffect(() => {
        const fetchUsers = async () => {
            try {
                const response = await api.get('/admin/users');
                setUsers(response.data);
            } catch (err) {
                setError('An error occurred while fetching users.');
            }
        };
        fetchUsers();
    }, []);

    const handleShowModal = (userId) => {
        setUserToDelete(userId);
        setShowModal(true);
    };

    const handleCloseModal = () => {
        setShowModal(false);
        setUserToDelete(null);
    };

    const handleDeleteUser = async () => {
        try {
            await api.delete(`/admin/users/${userToDelete}`);
            setUsers(users.filter((user) => user._id !== userToDelete));
            handleCloseModal();
        } catch (err) {
            setError('An error occurred while deleting user.');
        }
    };

    const handleSetStatus = async (userId, desiredStatus) => {
        try {
            await api.put(`/admin/users/${userId}`, { isActive: desiredStatus });
            setUsers(users.map((user) =>
                user._id === userId ? { ...user, isActive: desiredStatus } : user
            ));
        } catch (err) {
            setError('An error occurred while setting user status.');
        }
    };

    return (
        <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="max-w-7xl mx-auto my-8 px-4 sm:px-6 space-y-6">

            <div className="flex items-center gap-3 mb-8">
                <div className="p-2 bg-charcoal text-white rounded-lg"><Users size={24} /></div>
                <div>
                    <h1 className="text-3xl font-heading font-bold text-brandText">User Registry</h1>
                    <p className="text-sm text-brandText-muted">Manage system access and account vitality.</p>
                </div>
            </div>

            {error && (
                <div className="p-4 mb-6 bg-red-50 text-red-600 rounded-xl flex items-center gap-3 font-medium text-sm border border-red-100">
                    <ShieldAlert size={18} /> {error}
                </div>
            )}

            {/* Tailwind Data Table */}
            <div className="bg-surface rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-gray-50/50 border-b border-gray-100">
                                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Account Identity</th>
                                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Role</th>
                                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Status</th>
                                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Registration Date</th>
                                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {users.length > 0 ? users.map((user) => (
                                <tr key={user._id} className="hover:bg-gray-50/50 transition-colors">
                                    <td className="px-6 py-4 whitespace-nowrap font-medium text-brandText">
                                        {user.email}
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <span className={clsx("inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-semibold capitalize", user.role === 'admin' ? "bg-charcoal text-white" : "bg-gray-100 text-gray-700")}>
                                            {user.role === 'admin' && <Shield size={12} />} {user.role}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <span className={clsx("inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-semibold", user.isActive ? "bg-green-50 text-green-700 border border-green-200" : "bg-red-50 text-red-700 border border-red-200")}>
                                            <div className={clsx("w-1.5 h-1.5 rounded-full", user.isActive ? "bg-green-500" : "bg-red-500")} />
                                            {user.isActive ? 'Active' : 'Deactivated'}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-brandText-muted">
                                        {new Date(user.createdAt).toLocaleDateString()}
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-right">
                                        <div className="flex justify-end gap-2">
                                            {user.isActive ? (
                                                <button 
                                                    onClick={() => handleSetStatus(user._id, false)}
                                                    className="px-3 py-1.5 bg-amber-50 text-amber-700 hover:bg-amber-100 text-xs font-semibold rounded-lg flex items-center gap-1.5 transition-colors border border-amber-200"
                                                >
                                                    <PowerOff size={14} /> Deactivate
                                                </button>
                                            ) : (
                                                <button 
                                                    onClick={() => handleSetStatus(user._id, true)}
                                                    className="px-3 py-1.5 bg-green-50 text-green-700 hover:bg-green-100 text-xs font-semibold rounded-lg flex items-center gap-1.5 transition-colors border border-green-200"
                                                >
                                                    <Power size={14} /> Activate
                                                </button>
                                            )}
                                            <button 
                                                onClick={() => handleShowModal(user._id)}
                                                className="px-3 py-1.5 bg-red-50 text-red-700 hover:bg-red-100 text-xs font-semibold rounded-lg flex items-center gap-1.5 transition-colors border border-red-200"
                                            >
                                                <Trash2 size={14} /> Delete
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            )) : (
                                <tr>
                                    <td colSpan="5" className="px-6 py-8 text-center text-brandText-muted">No users found.</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Custom Tailwind Modal for Delete confirmation */}
            <AnimatePresence>
                {showModal && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm p-4">
                        <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="bg-surface rounded-3xl p-6 shadow-xl w-full max-w-sm border border-gray-100">
                            <div className="w-12 h-12 rounded-full bg-red-100 text-red-600 flex items-center justify-center mb-4">
                                <AlertCircle size={24} />
                            </div>
                            <h2 className="text-xl font-heading font-bold text-brandText mb-2">Delete User?</h2>
                            <p className="text-brandText-muted mb-6">Are you sure you want to permanently delete this user? Their account and associated data will be removed. This action cannot be undone.</p>
                            <div className="flex gap-3 justify-end mt-4">
                                <button onClick={handleCloseModal} className="px-4 py-2 bg-gray-100 text-brandText font-semibold rounded-xl hover:bg-gray-200 transition-colors">
                                    Cancel
                                </button>
                                <button onClick={handleDeleteUser} className="px-4 py-2 bg-red-500 text-white font-semibold rounded-xl hover:bg-red-600 shadow-sm transition-colors">
                                    Permanently Delete
                                </button>
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </motion.div>
    );
}

